import boto3
import os
import sys

def list_s3_files(bucket_name):
    """
    Lists all files in the specified S3 bucket.
    
    Args:
        bucket_name: Name of the S3 bucket
    """
    # Retrieve credentials from environment variables
    aws_access_key = os.environ.get('AWS_ACCESS_KEY_ID')
    aws_secret_key = os.environ.get('AWS_SECRET_ACCESS_KEY')
    aws_region = os.environ.get('AWS_DEFAULT_REGION', 'us-east-1')
    
    if not aws_access_key or not aws_secret_key:
        print("Error: AWS credentials not found in environment variables.")
        print("Please set the following environment variables:")
        print("  - AWS_ACCESS_KEY_ID")
        print("  - AWS_SECRET_ACCESS_KEY")
        print("  - AWS_DEFAULT_REGION (optional, defaults to us-east-1)")
        sys.exit(1)
    
    try:
        # Create S3 client with credentials from environment
        s3_client = boto3.client(
            's3',
            aws_access_key_id=aws_access_key,
            aws_secret_access_key=aws_secret_key,
            region_name=aws_region
        )
        
        print(f"Connecting to bucket: {bucket_name}")
        print("-" * 50)
        
        # List objects in the bucket
        response = s3_client.list_objects_v2(Bucket=bucket_name)
        
        if 'Contents' in response:
            print(f"Files in bucket '{bucket_name}':\n")
            for obj in response['Contents']:
                print(f"  - {obj['Key']} (Size: {obj['Size']} bytes, Last Modified: {obj['LastModified']})")
            print(f"\nTotal files: {len(response['Contents'])}")
        else:
            print(f"No files found in bucket '{bucket_name}'")
            
    except Exception as e:
        print(f"Error accessing S3 bucket: {str(e)}")
        sys.exit(1)

if __name__ == "__main__":
    bucket_name = 'demo-bucket'
    list_s3_files(bucket_name)